func checkWinner(b [9]string) (int, []int) {
	lines := [][3]int{
		{0, 1, 2}, {3, 4, 5}, {6, 7, 8}, // rows
		{0, 3, 6}, {1, 4, 7}, {2, 5, 8}, // cols
		{0, 4, 8}, {2, 4, 6},             // diags
	}

	for _, line := range lines {
		if b[line[0]] != "" && b[line[0]] == b[line[1]] && b[line[1]] == b[line[2]] {
			player := 0
			if b[line[0]] == "X" {
				player = 1
			} else {
				player = 2
			}
			return player, []int{line[0], line[1], line[2]}
		}
	}
	return 0, nil
}

